format.value:

if(mDynamicColData!=null&&mDynamicColData.size()>0)
	{//查询到了统计数据，对它进行格式化
		Iterator itKeys=mDynamicColData.keySet().iterator();
		while(itKeys.hasNext())
		{
			String key=(String)itKeys.next();
			String value=(String)mDynamicColData.get(key);
			if(key.indexOf("_EXAM_YEAR_")==0)
			{//如果是年

			 	if(value!=null&&!value.trim().equals(""))
			 		mDynamicColData.put(key,value+"年");
			}else if(key.indexOf("_EXAM_Q_")==0)
			{//如果是季度
				if(value==null) value="";
				if(value.equals("01")) value="一季度";
				else if(value.equals("02")) value="二季度";
				else if(value.equals("03")) value="三季度";
				else if(value.equals("04")) value="四季度";
			 	mDynamicColData.put(key,value);
			}
		}
	}
